/**
 * @summary Look up an invite by token (player)
 */
export const getLookupInviteUrl = (params: LookupInviteParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/invites/lookup?${stringifiedParams}`
    : `/api/invites/lookup`;
};

export const lookupInvite = async (
  params: LookupInviteParams,
  options?: RequestInit,
): Promise<InviteLookup> => {
  return customFetch<InviteLookup>(getLookupInviteUrl(params), {
    ...options,
    method: "GET",
  });
};

